#!/usr/bin/env node
/**
 * Post-generate script to patch zod-prisma-types output
 * Fixes known bugs in the generated file:
 * - NullTypes is used but not imported (zod-prisma-types bug)
 * - @prisma/client/runtime/library not resolvable
 */

import { readFileSync, writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const zodIndexPath = join(__dirname, '../shared/src/generated/zod/index.ts');

// eslint-disable-next-line no-console
console.log('🔧 Patching zod-prisma-types output...');

let content = readFileSync(zodIndexPath, 'utf-8');

// 1. Add @ts-nocheck and eslint-disable at the beginning to bypass type checking and linting for generated code
const tsNoCheck = '/* eslint-disable */\n// @ts-nocheck\n// This file is auto-generated by zod-prisma-types and patched by patch-zod-types.mjs\n\n';
if (!content.startsWith('/* eslint-disable */')) {
  content = tsNoCheck + content;
}

// 2. Replace problematic @prisma/client/runtime/library import with inline types
const problematicImport = /import \{ JsonValue, InputJsonValue, objectEnumValues, Decimal as PrismaDecimal, DecimalJsLike \} from '@prisma\/client\/runtime\/library';/;
const inlineTypes = `import Decimal from 'decimal.js';

// Inline type definitions (zod-prisma-types patch)
type JsonValue = string | number | boolean | null | JsonValue[] | { [key: string]: JsonValue };
type InputJsonValue = string | number | boolean | null | InputJsonValue[] | { [key: string]: InputJsonValue };
type DecimalJsLike = { d: number[]; e: number; s: number; toFixed: () => string };
const objectEnumValues = { instances: { DbNull: Symbol('DbNull'), JsonNull: Symbol('JsonNull') } };
const PrismaDecimal = Decimal; // Use decimal.js class`;
content = content.replace(problematicImport, inlineTypes);

// 2. Remove or fix Prisma type import if not used properly
content = content.replace(
  /import type \{ Prisma \} from '@sync-erp\/database\/client';?\n/g,
  ''
);

// 3. Remove original Decimal import if it exists BEFORE the replacement (not the one we added)
// (No longer needed - we keep the Decimal import we add in step 2)

// 4. Add NullTypes definition if not present
if (content.includes('NullTypes.') && !content.includes('const NullTypes')) {
  const NullTypesDefinition = `
// NullTypes polyfill (zod-prisma-types bug fix)
const NullTypes = {
  DbNull: Symbol('DbNull'),
  JsonNull: Symbol('JsonNull'),
  AnyNull: Symbol('AnyNull'),
} as const;
`;
  // Insert after imports
  content = content.replace(
    /^(import \{ z \} from 'zod';)\n/m,
    `$1\n${NullTypesDefinition}`
  );
}

writeFileSync(zodIndexPath, content, 'utf-8');
// eslint-disable-next-line no-console
console.log('✅ Patched zod index.ts successfully');
